/* ════════════════════════════════════════════════════════════════
   Aura Decore — Premium Motion & Interactivity Engine v2.0
   THEO + LUNA · Aura Decore 2026
   Dependências: GSAP 3 + ScrollTrigger (via CDN, injetado abaixo)
   Colar em: Online Store → Themes → Edit code → assets/aura-animations.js
   ════════════════════════════════════════════════════════════════ */

(function () {
  'use strict';

  /* ── Aguarda GSAP estar disponível ─────────────────────────── */
  function waitForGSAP(cb, tries) {
    tries = tries || 0;
    if (typeof gsap !== 'undefined' && typeof ScrollTrigger !== 'undefined') {
      gsap.registerPlugin(ScrollTrigger);
      cb();
    } else if (tries < 80) {
      setTimeout(function () { waitForGSAP(cb, tries + 1); }, 100);
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 1 — Custom Cursor + Cursor Trail de Partículas
  ════════════════════════════════════════════════════════════ */
  function initCursor() {
    if (window.matchMedia('(max-width: 749px)').matches) return;
    if (window.matchMedia('(pointer: coarse)').matches) return;

    var dot  = document.createElement('div');
    var ring = document.createElement('div');
    dot.className  = 'aura-cursor';
    ring.className = 'aura-cursor-ring';
    document.body.appendChild(dot);
    document.body.appendChild(ring);

    var mx = -100, my = -100;
    var rx = -100, ry = -100;

    document.addEventListener('mousemove', function (e) {
      mx = e.clientX; my = e.clientY;
      gsap.set(dot, { x: mx, y: my });
      spawnTrailParticle(mx, my);
    });

    gsap.ticker.add(function () {
      rx += (mx - rx) * 0.12;
      ry += (my - ry) * 0.12;
      gsap.set(ring, { x: rx, y: ry });
    });

    document.querySelectorAll('a, button, [role="button"], .card, input, textarea, select, label').forEach(function (el) {
      el.addEventListener('mouseenter', function () {
        dot.classList.add('aura-cursor--hover');
        ring.classList.add('aura-cursor-ring--hover');
      });
      el.addEventListener('mouseleave', function () {
        dot.classList.remove('aura-cursor--hover');
        ring.classList.remove('aura-cursor-ring--hover');
      });
    });

    document.addEventListener('mousedown', function () { dot.classList.add('aura-cursor--click'); });
    document.addEventListener('mouseup',   function () { dot.classList.remove('aura-cursor--click'); });
  }

  /* ── Cursor Trail de Faíscas ───────────────────────────────── */
  var trailPool = [];
  var trailIndex = 0;
  var POOL_SIZE = 18;

  function buildTrailPool() {
    if (window.matchMedia('(max-width: 749px)').matches) return;
    if (window.matchMedia('(pointer: coarse)').matches) return;
    for (var i = 0; i < POOL_SIZE; i++) {
      var p = document.createElement('div');
      p.className = 'aura-trail-dot';
      document.body.appendChild(p);
      trailPool.push(p);
    }
  }

  var lastTrailTime = 0;
  function spawnTrailParticle(x, y) {
    if (!trailPool.length) return;
    var now = Date.now();
    if (now - lastTrailTime < 40) return; // máx 25fps
    lastTrailTime = now;

    var p = trailPool[trailIndex % POOL_SIZE];
    trailIndex++;
    var size = 3 + Math.random() * 4;
    gsap.set(p, {
      x: x + (Math.random() - 0.5) * 8,
      y: y + (Math.random() - 0.5) * 8,
      width: size, height: size,
      opacity: 0.7,
      scale: 1,
    });
    gsap.to(p, {
      y: y - 20 - Math.random() * 20,
      x: x + (Math.random() - 0.5) * 30,
      opacity: 0,
      scale: 0,
      duration: 0.7 + Math.random() * 0.5,
      ease: 'power2.out',
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 2 — Scroll Progress Bar
  ════════════════════════════════════════════════════════════ */
  function initScrollProgress() {
    var bar = document.createElement('div');
    bar.className = 'aura-scroll-progress';
    document.body.appendChild(bar);

    window.addEventListener('scroll', function () {
      var scrolled = window.scrollY;
      var total    = document.documentElement.scrollHeight - window.innerHeight;
      var pct      = total > 0 ? (scrolled / total) * 100 : 0;
      bar.style.transform = 'scaleX(' + (pct / 100) + ')';
    }, { passive: true });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 3 — Header Scroll + Ícones magnéticos
  ════════════════════════════════════════════════════════════ */
  function initHeader() {
    var header = document.querySelector('.header-wrapper, .site-header, header[role="banner"]');
    if (!header) return;

    var THRESHOLD = 80;
    window.addEventListener('scroll', function () {
      if (window.scrollY > THRESHOLD) {
        header.classList.add('header--scrolled');
      } else {
        header.classList.remove('header--scrolled');
      }
    }, { passive: true });

    // Magnetic cart/search icons
    if (window.matchMedia('(max-width: 749px)').matches) return;
    header.querySelectorAll('.header__icon').forEach(function (icon) {
      icon.addEventListener('mousemove', function (e) {
        var rect = icon.getBoundingClientRect();
        var cx   = rect.left + rect.width  / 2;
        var cy   = rect.top  + rect.height / 2;
        var dx   = (e.clientX - cx) * 0.35;
        var dy   = (e.clientY - cy) * 0.35;
        gsap.to(icon, { x: dx, y: dy, duration: 0.3, ease: 'power2.out' });
      });
      icon.addEventListener('mouseleave', function () {
        gsap.to(icon, { x: 0, y: 0, duration: 0.5, ease: 'elastic.out(1, 0.5)' });
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 4 — Text Scramble no Hero
  ════════════════════════════════════════════════════════════ */
  var CHARS = 'アウラ•◆▲△AURA•·∙·◦○';

  function scrambleText(el, finalText, duration) {
    if (!el) return;
    var interval = null;
    var start    = Date.now();
    duration     = duration || 1200;
    var origLen  = finalText.length;

    interval = setInterval(function () {
      var elapsed  = Date.now() - start;
      var progress = Math.min(elapsed / duration, 1);
      var revealCount = Math.floor(progress * origLen);

      var result = '';
      for (var i = 0; i < origLen; i++) {
        if (i < revealCount) {
          result += finalText[i];
        } else if (finalText[i] === ' ' || finalText[i] === '\n') {
          result += finalText[i];
        } else {
          result += CHARS[Math.floor(Math.random() * CHARS.length)];
        }
      }
      el.textContent = result;

      if (progress >= 1) {
        clearInterval(interval);
        el.textContent = finalText;
      }
    }, 45);
  }

  function initHeroScramble() {
    var heading = document.querySelector('.banner__heading, .hero__title, .slideshow__slide-heading');
    if (!heading) return;
    var original = heading.textContent.trim();
    if (!original) return;

    setTimeout(function () {
      scrambleText(heading, original, 1400);
    }, 600);
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 5 — Hero Parallax + Mouse Follow
  ════════════════════════════════════════════════════════════ */
  function initHeroParallax() {
    var hero = document.querySelector('.banner, .hero, [data-section-type="image-banner"], .slideshow, section.image-banner');
    if (!hero) return;

    hero.classList.add('hero-parallax-wrapper');
    var bg = hero.querySelector('img, .banner__media, .media, video');
    if (bg) bg.classList.add('hero-parallax-bg');

    gsap.to(bg, {
      yPercent: 28,
      ease: 'none',
      scrollTrigger: { trigger: hero, start: 'top top', end: 'bottom top', scrub: 1.2 },
    });

    var targetX = 0, targetY = 0;
    var currentX = 0, currentY = 0;
    var STRENGTH = 16;

    document.addEventListener('mousemove', function (e) {
      targetX = (e.clientX / window.innerWidth  - 0.5) * STRENGTH;
      targetY = (e.clientY / window.innerHeight - 0.5) * STRENGTH;
    });

    gsap.ticker.add(function () {
      currentX += (targetX - currentX) * 0.06;
      currentY += (targetY - currentY) * 0.06;
      if (bg) gsap.set(bg, { x: currentX, y: currentY });

      hero.querySelectorAll('.banner__content .field, .banner__box, .hero__text-group').forEach(function (el, i) {
        var depth = (i % 3 + 1) * 0.4;
        gsap.set(el, { x: currentX * depth, y: currentY * depth * 0.5 });
      });
    });

    // Text stagger entrance
    var textEls = hero.querySelectorAll('.banner__heading, .banner__subheading, .hero__title, .hero__description, .banner__content a, .banner__buttons');
    textEls.forEach(function (el) { el.classList.add('hero-stagger-item'); });

    gsap.to(textEls, {
      opacity: 1, y: 0, duration: 1, stagger: 0.18, ease: 'power3.out', delay: 0.3,
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 6 — Split Text Reveal em Headings de Seção
  ════════════════════════════════════════════════════════════ */
  function initSplitTextReveal() {
    var TARGETS = '.section-header h2, .collection__title, .rich-text h2, .title--primary, .featured-collection__title';

    document.querySelectorAll(TARGETS).forEach(function (el) {
      if (el.closest('.aura-mid-banner')) return;
      var text  = el.innerHTML.trim();
      var words = text.split(' ');

      el.innerHTML = words.map(function (w) {
        return '<span class="aura-word-wrap"><span class="aura-word">' + w + '</span></span>';
      }).join(' ');

      var wordEls = el.querySelectorAll('.aura-word');

      ScrollTrigger.create({
        trigger: el,
        start: 'top 85%',
        onEnter: function () {
          gsap.to(wordEls, {
            y: 0,
            opacity: 1,
            duration: 0.7,
            stagger: 0.06,
            ease: 'power4.out',
          });
        },
        once: true,
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 7 — Magnetic Buttons
  ════════════════════════════════════════════════════════════ */
  function initMagneticButtons() {
    if (window.matchMedia('(max-width: 749px)').matches) return;

    var SELECTORS = 'button.button, a.button, .button--primary, .button--secondary, .aura-mid-banner__cta';

    document.querySelectorAll(SELECTORS).forEach(function (btn) {
      var STRENGTH = 0.42;

      btn.addEventListener('mousemove', function (e) {
        var rect = btn.getBoundingClientRect();
        var cx   = rect.left + rect.width  / 2;
        var cy   = rect.top  + rect.height / 2;
        var dx   = (e.clientX - cx) * STRENGTH;
        var dy   = (e.clientY - cy) * STRENGTH;
        gsap.to(btn, {
          x: dx, y: dy,
          duration: 0.35,
          ease: 'power2.out',
        });
      });

      btn.addEventListener('mouseleave', function () {
        gsap.to(btn, {
          x: 0, y: 0,
          duration: 0.6,
          ease: 'elastic.out(1, 0.45)',
        });
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 8 — Middle Banner Dinâmico
  ════════════════════════════════════════════════════════════ */
  function initMidBanner() {
    if (document.querySelector('.aura-mid-banner')) return;

    var sections = document.querySelectorAll('.shopify-section, section[class*="section"]');
    if (sections.length < 3) return;

    var heroImg = document.querySelector('.banner img, .hero img, .slideshow img');
    var bgUrl   = heroImg
      ? heroImg.src.replace(/(\.[^.]+)$/, '_2048x$1').replace(/&width=\d+/, '&width=2048')
      : '';

    var banner = document.createElement('div');
    banner.className = 'shopify-section aura-mid-banner';
    banner.setAttribute('data-aura-mid', 'true');
    if (bgUrl) banner.style.setProperty('--mid-bg', 'url("' + bgUrl + '")');

    banner.innerHTML = [
      '<div class="aura-mid-banner__bg" style="background-image: var(--mid-bg, linear-gradient(135deg, #2d1f14 0%, #4a3525 40%, #2d2318 100%));"></div>',
      '<div class="aura-mid-banner__overlay"></div>',
      '<div class="aura-mid-banner__noise"></div>',
      '<div class="aura-mid-banner__content">',
        '<span class="aura-mid-banner__eyebrow">Aura Decore — Japandi Living</span>',
        '<h2 class="aura-mid-banner__title">Um espaço que respira<br>intenção e beleza</h2>',
        '<p class="aura-mid-banner__subtitle">',
          'Cada peça da nossa coleção foi escolhida para trazer equilíbrio,<br>',
          'calma e sofisticação ao seu lar.',
        '</p>',
        '<a href="/collections/all" class="aura-mid-banner__cta"><span>Explorar coleção</span><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>',
      '</div>',
      '<div class="aura-particle" style="width:180px;height:180px;top:10%;left:5%;--duration:9s;--drift:-30px;--rot:15deg;opacity:0.06;"></div>',
      '<div class="aura-particle" style="width:80px;height:80px;top:70%;right:8%;--duration:7s;--drift:-20px;--rot:-10deg;opacity:0.1;animation-delay:-3s;"></div>',
      '<div class="aura-particle" style="width:260px;height:260px;bottom:-60px;right:-40px;--duration:12s;--drift:-15px;--rot:8deg;opacity:0.04;"></div>',
    ].join('');

    sections[1].insertAdjacentElement('afterend', banner);

    ScrollTrigger.create({
      trigger: banner,
      start: 'top 72%',
      onEnter: function () { banner.classList.add('aura-mid-banner--visible'); },
    });

    var midBg = banner.querySelector('.aura-mid-banner__bg');
    gsap.to(midBg, {
      yPercent: 18, ease: 'none',
      scrollTrigger: { trigger: banner, start: 'top bottom', end: 'bottom top', scrub: 1.5 },
    });

    // Mouse follow + ambient glow
    var tmx = 0, tmy = 0, cmx = 0, cmy = 0;
    banner.addEventListener('mousemove', function (e) {
      var rect = banner.getBoundingClientRect();
      tmx = (e.clientX - rect.left) / rect.width  - 0.5;
      tmy = (e.clientY - rect.top)  / rect.height - 0.5;
      // Spotlight segue o mouse
      var px = ((e.clientX - rect.left) / rect.width  * 100).toFixed(1);
      var py = ((e.clientY - rect.top)  / rect.height * 100).toFixed(1);
      banner.style.setProperty('--spotlight-x', px + '%');
      banner.style.setProperty('--spotlight-y', py + '%');
    });
    banner.addEventListener('mouseleave', function () { tmx = 0; tmy = 0; });

    gsap.ticker.add(function () {
      cmx += (tmx - cmx) * 0.07;
      cmy += (tmy - cmy) * 0.07;
      gsap.set(midBg, { x: cmx * 20, y: cmy * 12 });
    });

    // Ripple no CTA
    var cta = banner.querySelector('.aura-mid-banner__cta');
    if (cta) {
      cta.style.overflow = 'hidden';
      cta.style.position = 'relative';
      cta.addEventListener('click', function (e) {
        var ripple = document.createElement('span');
        ripple.className = 'aura-ripple';
        var rect = cta.getBoundingClientRect();
        var size = Math.max(rect.width, rect.height) * 2;
        ripple.style.cssText = 'width:' + size + 'px;height:' + size + 'px;left:' + (e.clientX - rect.left - size / 2) + 'px;top:' + (e.clientY - rect.top - size / 2) + 'px';
        cta.appendChild(ripple);
        ripple.addEventListener('animationend', function () { ripple.remove(); });
      });
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 9 — Ambient Card Glow (spotlight segue o mouse)
  ════════════════════════════════════════════════════════════ */
  function initCardAmbientGlow() {
    if (window.matchMedia('(max-width: 749px)').matches) return;

    document.querySelectorAll('.card, .card--product, .product-card').forEach(function (card) {
      card.addEventListener('mousemove', function (e) {
        var rect = card.getBoundingClientRect();
        var px = ((e.clientX - rect.left) / rect.width  * 100).toFixed(1);
        var py = ((e.clientY - rect.top)  / rect.height * 100).toFixed(1);
        card.style.setProperty('--glow-x', px + '%');
        card.style.setProperty('--glow-y', py + '%');
        card.classList.add('aura-card--glowing');
      });
      card.addEventListener('mouseleave', function () {
        card.classList.remove('aura-card--glowing');
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 10 — Product Card 3D Hover
  ════════════════════════════════════════════════════════════ */
  function initCardHover() {
    if (window.matchMedia('(max-width: 749px)').matches) return;

    document.querySelectorAll('.card, .card--product, .product-card').forEach(function (card) {
      var TILT_MAX = 9;

      card.addEventListener('mousemove', function (e) {
        var rect = card.getBoundingClientRect();
        var dx = (e.clientX - rect.left - rect.width  / 2) / (rect.width  / 2);
        var dy = (e.clientY - rect.top  - rect.height / 2) / (rect.height / 2);
        gsap.to(card, {
          rotateX: -dy * TILT_MAX,
          rotateY:  dx * TILT_MAX,
          transformPerspective: 900,
          ease: 'power2.out',
          duration: 0.4,
        });
      });

      card.addEventListener('mouseleave', function () {
        gsap.to(card, {
          rotateX: 0, rotateY: 0,
          ease: 'elastic.out(1, 0.5)',
          duration: 0.8,
        });
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 11 — Scroll Reveal Global (IntersectionObserver)
  ════════════════════════════════════════════════════════════ */
  function initScrollReveal() {
    var SELECTORS = [
      '.collection-list__item',
      '.product-grid > *',
      '.grid--2-col > *',
      '.grid--3-col > *',
      '.grid--4-col > *',
      '.featured-collection .card-wrapper',
      '.section-header',
      '.rich-text',
      '.image-with-text__content',
      '.image-with-text__media',
      '.multicolumn-list__item',
      '.blog-articles article',
      '.footer__column',
      '.footer__content-bottom',
    ];

    var candidates = document.querySelectorAll(SELECTORS.join(', '));
    var seen = new WeakSet();

    candidates.forEach(function (el, i) {
      if (seen.has(el)) return;
      seen.add(el);
      el.classList.add('aura-reveal');
      if (i % 3 === 1) el.classList.add('aura-reveal--scale');
    });

    var observer = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        if (entry.isIntersecting) {
          entry.target.classList.add('aura-reveal--visible');
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });

    document.querySelectorAll('.aura-reveal').forEach(function (el) { observer.observe(el); });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 12 — Brand Values Marquee
  ════════════════════════════════════════════════════════════ */
  function initMarquee() {
    if (document.querySelector('.aura-marquee')) return;

    var sections = document.querySelectorAll('.shopify-section');
    if (sections.length < 2) return;

    // Insere após a 1ª seção
    var marquee = document.createElement('div');
    marquee.className = 'shopify-section aura-marquee-section';

    var ITEMS = [
      '✦ Design Japandi',
      '✦ Qualidade Premium',
      '✦ Minimalismo Intencional',
      '✦ Entrega Segura',
      '✦ Elegância Natural',
      '✦ Materiais Sustentáveis',
    ];
    var track = '<div class="aura-marquee-track">' +
      ITEMS.map(function (t) { return '<span class="aura-marquee-item">' + t + '</span>'; }).join('') +
      ITEMS.map(function (t) { return '<span class="aura-marquee-item" aria-hidden="true">' + t + '</span>'; }).join('') +
    '</div>';

    marquee.innerHTML = '<div class="aura-marquee" aria-hidden="true">' + track + '</div>';
    sections[0].insertAdjacentElement('afterend', marquee);
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 13 — Image Clip-Path Reveal on Scroll
  ════════════════════════════════════════════════════════════ */
  function initImageReveal() {
    document.querySelectorAll('.image-with-text .image-with-text__media, .media-gallery__item').forEach(function (el) {
      el.classList.add('aura-img-reveal');

      ScrollTrigger.create({
        trigger: el,
        start: 'top 80%',
        onEnter: function () { el.classList.add('aura-img-reveal--visible'); },
        once: true,
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 14 — Button Ripple
  ════════════════════════════════════════════════════════════ */
  function initButtonRipple() {
    document.querySelectorAll(
      'button.button, a.button, .button--primary, .button--secondary, .cart__checkout-button, form[action="/cart"] button'
    ).forEach(function (btn) {
      btn.style.overflow = 'hidden';
      btn.style.position = 'relative';
      btn.addEventListener('click', function (e) {
        var ripple = document.createElement('span');
        ripple.className = 'aura-ripple';
        var rect = btn.getBoundingClientRect();
        var size = Math.max(rect.width, rect.height) * 2.5;
        ripple.style.cssText = 'width:' + size + 'px;height:' + size + 'px;left:' + (e.clientX - rect.left - size / 2) + 'px;top:' + (e.clientY - rect.top - size / 2) + 'px';
        btn.appendChild(ripple);
        ripple.addEventListener('animationend', function () { ripple.remove(); });
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 15 — Seções com GSAP ScrollTrigger
  ════════════════════════════════════════════════════════════ */
  function initSectionAnimations() {
    // Featured collection grid stagger
    document.querySelectorAll('.featured-collection, .collection-list, .product-recommendations').forEach(function (section) {
      var items = section.querySelectorAll('.card-wrapper, .collection-list__item');
      if (!items.length) return;
      items.forEach(function (el) { el.classList.remove('aura-reveal'); });

      gsap.from(items, {
        opacity: 0, y: 48, scale: 0.95,
        duration: 0.8, stagger: 0.1, ease: 'power3.out',
        scrollTrigger: { trigger: section, start: 'top 78%', toggleActions: 'play none none none' },
      });
    });

    // Image-with-text split entrance
    document.querySelectorAll('.image-with-text').forEach(function (section) {
      var media   = section.querySelector('.image-with-text__media');
      var content = section.querySelector('.image-with-text__content');
      if (media) gsap.from(media, {
        opacity: 0, x: -60, duration: 1.1, ease: 'power3.out',
        scrollTrigger: { trigger: section, start: 'top 80%', toggleActions: 'play none none none' },
      });
      if (content) gsap.from(content, {
        opacity: 0, x: 60, duration: 1.1, ease: 'power3.out',
        scrollTrigger: { trigger: section, start: 'top 80%', toggleActions: 'play none none none' },
      });
    });

    // Rich text / multicolumn
    document.querySelectorAll('.rich-text__blocks > *, .multicolumn-list__item').forEach(function (el, i) {
      el.classList.remove('aura-reveal');
      gsap.from(el, {
        opacity: 0, y: 36, duration: 0.8, delay: i * 0.09, ease: 'power3.out',
        scrollTrigger: { trigger: el, start: 'top 85%', toggleActions: 'play none none none' },
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 16 — Footer reveal GSAP
  ════════════════════════════════════════════════════════════ */
  function initFooter() {
    var footer = document.querySelector('.footer, .site-footer');
    if (!footer) return;

    var columns = footer.querySelectorAll('.footer__column, .footer-block, .site-footer__column');
    columns.forEach(function (col) { col.classList.remove('aura-reveal'); });

    gsap.from(columns, {
      opacity: 0, y: 32, stagger: 0.12, duration: 0.85, ease: 'power3.out',
      scrollTrigger: { trigger: footer, start: 'top 88%', toggleActions: 'play none none none' },
    });

    var bottom = footer.querySelector('.footer__content-bottom');
    if (bottom) {
      bottom.classList.remove('aura-reveal');
      gsap.from(bottom, {
        opacity: 0, y: 18, duration: 0.7, ease: 'power3.out',
        scrollTrigger: { trigger: bottom, start: 'top 95%', toggleActions: 'play none none none' },
      });
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 17 — Breathing + Pulse em elementos decorativos
  ════════════════════════════════════════════════════════════ */
  function initBreathe() {
    document.querySelectorAll(
      '.trust-badges img, .icon-with-text__icon, .newsletter__icon, .announcement-bar__message'
    ).forEach(function (el) {
      el.classList.add('aura-breathe');
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 18 — Counter / Número Animado
  ════════════════════════════════════════════════════════════ */
  function initCounters() {
    document.querySelectorAll('[data-aura-count]').forEach(function (el) {
      var target = parseInt(el.getAttribute('data-aura-count'), 10);
      if (isNaN(target)) return;

      ScrollTrigger.create({
        trigger: el,
        start: 'top 85%',
        once: true,
        onEnter: function () {
          gsap.to({ val: 0 }, {
            val: target,
            duration: 2,
            ease: 'power2.out',
            onUpdate: function () {
              el.textContent = Math.round(this.targets()[0].val).toLocaleString('pt-BR');
            },
          });
        },
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     BOOT — inicializa tudo
  ════════════════════════════════════════════════════════════ */
  function boot() {
    buildTrailPool();
    initCursor();
    initScrollProgress();
    initHeader();
    initHeroScramble();
    initHeroParallax();
    initScrollReveal();
    initCardHover();
    initCardAmbientGlow();
    initButtonRipple();
    initBreathe();
    initMarquee();

    waitForGSAP(function () {
      initMidBanner();
      initSplitTextReveal();
      initMagneticButtons();
      initSectionAnimations();
      initFooter();
      initImageReveal();
      initCounters();

      setTimeout(function () { ScrollTrigger.refresh(); }, 600);
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

})();
